  1	import {
  2	  Button,
  3	  Card,
  4	  CardBody,
  5	  Flex,
  6	  Grid,
  7	  PageSection,
  8	  Title,
  9	  Tooltip,
 10	} from '@patternfly/react-core';
 11	import { SyncAltIcon } from '@patternfly/react-icons';
 12	import React from 'react';
 13	import { useTranslation } from 'react-i18next';
 14	import {
 15	  availableAttributes,
 16	  filtersFromQuery,
 17	  initialAvailableAttributes,
 18	  queryFromFilters,
 19	} from '../attribute-filters';
 20	import { CenteredContainer } from '../components/centered-container';
 21	import { Filters } from '../components/filters/filter.types';
 22	import { LogsHistogram } from '../components/logs-histogram';
 23	import { LogsMetrics } from '../components/logs-metrics';
 24	import { LogsTable } from '../components/logs-table';
 25	import { LogsToolbar } from '../components/logs-toolbar';
 26	import { RefreshIntervalDropdown } from '../components/refresh-interval-dropdown';
 27	import { TimeRangeDropdown } from '../components/time-range-dropdown';
 28	import { TimezoneDropdown } from '../components/timezone-dropdown';
 29	import { ToggleHistogramButton } from '../components/toggle-histogram-button';
 30	import { downloadCSV } from '../download-csv';
 31	import { LogsConfigProvider, useLogsConfig } from '../hooks/LogsConfigProvider';
 32	import { useLogs } from '../hooks/useLogs';
 33	import { defaultQueryFromTenant, useURLState } from '../hooks/useURLState';
 34	import { Direction, isMatrixResult } from '../logs.types';
 35	import { TestIds } from '../test-ids';
 36	
 37	const LogsPage: React.FC = () => {
 38	  const { t } = useTranslation('plugin__logging-view-plugin');
 39	
 40	  const [isHistogramVisible, setIsHistogramVisible] = React.useState(false);
 41	
 42	  const { config, configLoaded } = useLogsConfig();
 43	
 44	  const {
 45	    histogramData,
 46	    histogramError,
 47	    isLoadingLogsData,
 48	    isLoadingMoreLogsData,
 49	    isLoadingHistogramData,
 50	    isLoadingVolumeData,
 51	    volumeError,
 52	    showVolumeGraph,
 53	    isStreaming,
 54	    logsData,
 55	    volumeData,
 56	    logsError,
 57	    getLogs,
 58	    getVolume,
 59	    getMoreLogs,
 60	    hasMoreLogsData,
 61	    getHistogram,
 62	    toggleStreaming,
 63	  } = useLogs();
 64	
 65	  const {
 66	    query,
 67	    setQueryInURL,
 68	    tenant,
 69	    setTenantInURL,
 70	    schema,
 71	    setSchemaInURL,
 72	    areResourcesShown,
 73	    setShowResourcesInURL,
 74	    areStatsShown,
 75	    setShowStatsInURL,
 76	    filters,
 77	    setFilters,
 78	    setTimeRangeInURL,
 79	    timeRange,
 80	    interval,
 81	    direction,
 82	    setDirectionInURL,
 83	    timezone,
 84	    setTimezoneInURL,
 85	    attributes,
 86	  } = useURLState({
 87	    getAttributes: availableAttributes,
 88	  });
 89	
 90	  const handleToggleStreaming = () => {
 91	    toggleStreaming({ query, schema });
 92	  };
 93	
 94	  const handleLoadMoreData = (lastTimestamp: number) => {
 95	    if (!isLoadingMoreLogsData) {
 96	      getMoreLogs({ lastTimestamp, query, direction, schema });
 97	    }
 98	  };
 99	
100	  const handleSortByDate = (directionValue?: Direction) => {
101	    setDirectionInURL(directionValue);
102	  };
103	
104	  const runQuery = ({ queryToUse }: { queryToUse?: string } = {}) => {
105	    getLogs({ query: queryToUse ?? query, tenant, timeRange, direction, schema });
106	
107	    if (isHistogramVisible) {
108	      getHistogram({ query: queryToUse ?? query, tenant, timeRange, schema });
109	    }
110	  };
111	
112	  const runVolume = () => {
113	    getVolume({ query, tenant, timeRange, schema });
114	  };
115	
116	  const handleFiltersChange = (selectedFilters?: Filters) => {
117	    setFilters(selectedFilters);
118	    updateQuery(selectedFilters, tenant);
119	  };
120	
121	  const handleQueryChange = (queryFromInput: string) => {
122	    setQueryInURL(queryFromInput);
123	
124	    const updatedFilters = filtersFromQuery({
125	      query: queryFromInput,
126	      attributes: initialAvailableAttributes(schema),
127	      schema: schema,
128	    });
129	
130	    setFilters(updatedFilters);
131	  };
132	
133	  const updateQuery = (selectedFilters?: Filters, selectedTenant?: string): string => {
134	    if ((!selectedFilters || Object.keys(selectedFilters).length === 0) && !selectedTenant) {
135	      const defaultQuery = defaultQueryFromTenant({ schema });
136	
137	      setQueryInURL(defaultQuery);
138	
139	      return defaultQuery;
140	    } else {
141	      const updatedQuery = queryFromFilters({
142	        existingQuery: query,
143	        filters: selectedFilters,
144	        attributes: initialAvailableAttributes(schema),
145	        tenant: selectedTenant,
146	        schema,
147	      });
148	
149	      setQueryInURL(updatedQuery);
150	
151	      return updatedQuery;
152	    }
153	  };
154	
155	  const handleRefreshClick = () => {
156	    runQuery();
157	  };
158	
159	  React.useEffect(() => {
160	    if (!configLoaded) {
161	      return;
162	    }
163	
164	    const queryToUse = updateQuery(filters, tenant);
165	
166	    runQuery({ queryToUse });
167	  }, [timeRange, isHistogramVisible, direction, tenant, configLoaded]);
168	
169	  const isQueryEmpty = query === '';
170	
171	  const resultIsMetric = isMatrixResult(logsData?.data);
172	
173	  React.useEffect(() => {
174	    if (resultIsMetric) {
175	      setIsHistogramVisible(false);
176	    }
177	  }, [resultIsMetric]);
178	
179	  return (
180	    <PageSection>
181	      <Grid hasGutter>
182	        <Flex justifyContent={{ default: 'justifyContentSpaceBetween' }}>
183	          <Title headingLevel="h1" size="lg">
184	            {t('Logs')}
185	          </Title>
186	          <Flex>
187	            <ToggleHistogramButton
188	              isToggled={isHistogramVisible}
189	              onToggle={() => setIsHistogramVisible(!isHistogramVisible)}
190	              data-test={TestIds.ToggleHistogramButton}
191	              isDisabled={resultIsMetric}
192	            />
193	            <TimeRangeDropdown
194	              value={timeRange}
195	              onChange={setTimeRangeInURL}
196	              isDisabled={isQueryEmpty}
197	              timezone={timezone}
198	            />
199	            {config.showTimezoneSelector && (
200	              <TimezoneDropdown
201	                value={timezone}
202	                onChange={setTimezoneInURL}
203	                isDisabled={isQueryEmpty}
204	              />
205	            )}
206	            <RefreshIntervalDropdown onRefresh={runQuery} isDisabled={isQueryEmpty} />
207	            <Tooltip content={<div>Refresh</div>}>
208	              <Button
209	                onClick={handleRefreshClick}
210	                aria-label="Refresh"
211	                variant="secondary"
212	                data-test={TestIds.SyncButton}
213	                isDisabled={isQueryEmpty}
214	              >
215	                <SyncAltIcon />
216	              </Button>
217	            </Tooltip>
218	          </Flex>
219	        </Flex>
220	
221	        {isHistogramVisible && !resultIsMetric && (
222	          <LogsHistogram
223	            histogramData={histogramData}
224	            timeRange={timeRange}
225	            interval={interval}
226	            isLoading={isLoadingHistogramData}
227	            error={histogramError}
228	            onChangeTimeRange={setTimeRangeInURL}
229	            schema={schema}
230	            timezone={timezone}
231	          />
232	        )}
233	        <LogsToolbar
234	          query={query}
235	          onQueryChange={handleQueryChange}
236	          onQueryRun={runQuery}
237	          onVolumeRun={runVolume}
238	          onTenantSelect={setTenantInURL}
239	          tenant={tenant}
240	          isStreaming={isStreaming}
241	          onStreamingToggle={handleToggleStreaming}
242	          enableStreaming={config.isStreamingEnabledInDefaultPage}
243	          showResources={areResourcesShown}
244	          onShowResourcesToggle={setShowResourcesInURL}
245	          showStats={areStatsShown}
246	          onShowStatsToggle={setShowStatsInURL}
247	          isDisabled={isQueryEmpty}
248	          attributeList={attributes}
249	          filters={filters}
250	          onFiltersChange={handleFiltersChange}
251	          onDownloadCSV={() => downloadCSV(logsData)}
252	          schema={schema}
253	          onSchemaSelect={setSchemaInURL}
254	        />
255	
256	        {isLoadingLogsData ? (
257	          <CenteredContainer>{t('Loading...')}</CenteredContainer>
258	        ) : showVolumeGraph ? (
259	          <Card>
260	            <CardBody>
261	              <LogsMetrics
262	                logsData={volumeData}
263	                timeRange={timeRange}
264	                isLoading={isLoadingVolumeData}
265	                error={volumeError}
266	                height={350}
267	                timezone={timezone}
268	                displayLegendTable
269	              />
270	            </CardBody>
271	          </Card>
272	        ) : resultIsMetric ? (
273	          <Card>
274	            <CardBody>
275	              <LogsMetrics
276	                logsData={logsData}
277	                timeRange={timeRange}
278	                isLoading={isLoadingLogsData}
279	                error={logsError}
280	                height={350}
281	                timezone={timezone}
282	                displayLegendTable
283	              />
284	            </CardBody>
285	          </Card>
286	        ) : (
287	          <LogsTable
288	            logsData={logsData}
289	            onLoadMore={handleLoadMoreData}
290	            onSortByDate={handleSortByDate}
291	            isLoading={isLoadingLogsData}
292	            isLoadingMore={isLoadingMoreLogsData}
293	            hasMoreLogsData={hasMoreLogsData}
294	            showResources={areResourcesShown}
295	            showStats={areStatsShown}
296	            direction={direction}
297	            isStreaming={isStreaming}
298	            error={logsError}
299	            timezone={timezone}
300	            hasNamespaceFilter={Boolean(filters?.namespace?.size)}
301	            schema={schema}
302	          />
303	        )}
304	      </Grid>
305	    </PageSection>
306	  );
307	};
308	
309	const LogsPageWrapper: React.FC = () => {
310	  return (
311	    <LogsConfigProvider>
312	      <LogsPage />
313	    </LogsConfigProvider>
314	  );
315	};
316	
317	export default LogsPageWrapper;

